fn main() {
    let s = String::from("hello world");
    let hello = &s[..5];
    let world = &s[6..];
    println!("{} | {}", hello, world);
}

fn main() {
    let arr = [1, 2, 3, 4, 5];
    let middle = &arr[1..4];
    println!("{:?}", middle);
    println!("len: {}", middle.len());
}

fn sum(nums: &[i32]) -> i32 {
    let mut total = 0;
    for &n in nums {
        total += n;
    }
    total
}

fn main() {
    let v = [10, 20, 30, 40, 50];
    println!("{}", sum(&v));
    println!("{}", sum(&v[1..4]));
}

fn main() {
    let primes = [2, 3, 5, 7, 11];
    for &p in &primes {
        print!("{} ", p);
    }
    println!();
}

fn scale(slice: &mut [i32], factor: i32) {
    for x in slice {
        *x *= factor;
    }
}

fn main() {
    let mut data = [1, 2, 3, 4, 5];
    scale(&mut data[1..4], 10);
    println!("{:?}", data);
}

fn main() {
    let mut v = [5, 2, 8, 1, 9, 3];
    v.sort();
    println!("{:?}", v);
    println!("first={:?} last={:?}", v.first(), v.last());
    println!("contains 8: {}", v.contains(&8));
}

fn main() {
    let arr = [1, 2, 3, 4, 5, 6];
    let (left, right) = arr.split_at(3);
    println!("left: {:?}", left);
    println!("right: {:?}", right);
}

fn main() {
    let data = [1, 2, 3, 4, 5];
    for w in data.windows(3) {
        print!("{:?} ", w);
    }
    println!();
    for c in data.chunks(2) {
        print!("{:?} ", c);
    }
    println!();
}
